/**
 * 文件依赖加载
 * 算法：建树 + DFS 收集后代 + 排序
 * 时间复杂度 O(n log n)
 */
#define MAX_N 1005
static int cmp_int(const void* a, const void* b) { return (*(int*)a - *(int*)b); }
int* getLoadedFileIds(int* fileIds, int fileIdsSize, int* parentIds, int parentIdsSize,
                      int targetId, int* returnSize) {
    int** children = (int**)malloc(MAX_N * sizeof(int*));
    int* childCnt = (int*)calloc(MAX_N, sizeof(int));
    int* childCap = (int*)calloc(MAX_N, sizeof(int));
    for (int i = 0; i < MAX_N; i++) { childCap[i] = 4; children[i] = (int*)malloc(4 * sizeof(int)); }
    for (int i = 0; i < fileIdsSize; i++) {
        int pid = parentIds[i], fid = fileIds[i];
        if (pid < 0 || pid >= MAX_N) continue;
        if (childCnt[pid] >= childCap[pid]) { childCap[pid] *= 2; children[pid] = realloc(children[pid], childCap[pid] * sizeof(int)); }
        children[pid][childCnt[pid]++] = fid;
    }
    int* ans = (int*)malloc(MAX_N * sizeof(int)), ansCnt = 0;
    int* stack = (int*)malloc(MAX_N * sizeof(int)), top = 0;
    stack[top++] = targetId;
    while (top > 0) {
        int u = stack[--top]; ans[ansCnt++] = u;
        for (int i = 0; i < childCnt[u]; i++) stack[top++] = children[u][i];
    }
    qsort(ans, ansCnt, sizeof(int), cmp_int);
    for (int i = 0; i < MAX_N; i++) free(children[i]);
    free(children); free(childCnt); free(childCap); free(stack);
    *returnSize = ansCnt; return ans;
}
